package ir.tahamohamadi.blog.category;
import ir.tahamohamadi.common.domain.LanguageCode; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*; import java.time.Instant; import java.util.*;
@Entity @Table(name="blog_category_translation") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class BlogCategoryTranslation extends AuditedSoftDeletableEntity { @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="blog_category_id",nullable=false) private BlogCategory category; @Enumerated(EnumType.STRING) @Column(name="language_code",nullable=false,length=2) private LanguageCode languageCode; @Column(nullable=false,length=255) private String name; @Column(nullable=false,length=255) private String slug; @Column(name="seo_title",length=255) private String seoTitle; @Column(name="seo_description",length=500) private String seoDescription; private BlogCategoryTranslation(UUID id,BlogCategory category,LanguageCode language,String name,String slug,Instant at){initialize(id,at);this.category=Objects.requireNonNull(category);languageCode=Objects.requireNonNull(language);this.name=requireNonBlank(name,"name");this.slug=requireNonBlank(slug,"slug");} public static BlogCategoryTranslation create(UUID id,BlogCategory category,LanguageCode language,String name,String slug,Instant at){return new BlogCategoryTranslation(id,category,language,name,slug,at);} }
